import { updateTableWithCellData } from '../../../utils/table';
import { StateContext } from '../../App';

const { useContext } = wp.element;
const { __ } = wp.i18n;

const Buttons = () => {
	const { state, dispatch } = useContext( StateContext );
	const { table, activeCell } = state;

	/**
	 * @todo Save to database.
	 */
	const onHandleSave = () => {
		dispatch( { type: 'SET_TABLE', payload: updateTableWithCellData( table, activeCell ) } );
		dispatch( { type: 'UNSET_ACTIVE_CELL' } );
		dispatch( { type: 'SET_VIEW', payload: 'table' } );
		dispatch( { type: 'SAVE_TABLE' } );
	};

	/**
	 * @todo Show the alert.
	 */
	const onHandleCloseModal = () => {
		dispatch( { type: 'UNSET_ACTIVE_CELL' } );
		dispatch( { type: 'SET_VIEW', payload: 'table' } );
	};

	return (
		<div className={ 'advanced-wp-table-editor-action-buttons' }>
			<div>
				<button
					onClick={ onHandleSave }
					className={ 'button button-primary button-large' }
				>
					{ __( 'Save Changes', 'advanced-wp-table' ) }
				</button>
				{ ` ` }
				<button onClick={ onHandleCloseModal } className={ 'button button-large' }>
					{ __( 'Close', 'advanced-wp-table' ) }
				</button>
			</div>
		</div>
	);
};

export default Buttons;
