import { StateContext } from '../App';

const { useContext } = wp.element;
const { __ } = wp.i18n;

const Actions = ( { table } ) => {
	const stateContext = useContext( StateContext );
	const { dispatch } = stateContext;

	const handleNavigateToTable = () => {
		dispatch( { type: 'SET_TABLE', payload: table } );
		dispatch( { type: 'SET_VIEW', payload: 'table' } );
	};

	return (
		<div className={ 'row-actions' }>
			<span className={ 'edit' }>
				<button
					className={ 'button-link' }
					onClick={ handleNavigateToTable }
				>
					{ __( 'Edit', 'advanced-wp-table' ) }
				</button>
			</span>
			{ ` | ` }
			<span className={ 'duplicate' }>
				<button
					className={ 'button-link' }
				>
					{ __( 'Duplicate', 'advanced-wp-table' ) }
				</button>
			</span>
			{ ` | ` }
			<span className={ 'trash' }>
				<a href={ '#/' }>{ __( 'Trash', 'advanced-wp-table' ) }</a>
			</span>
		</div>
	);
};

export default Actions;
